mapper.select:
SELECT id, username, password, email, phone, status, email_verified,
       login_failures, locked_until, created_at, updated_at
FROM user WHERE username = #{username}

SELECT id, username, password, email, phone, status, email_verified,
       login_failures, locked_until, created_at, updated_at
FROM user WHERE id = #{id}

SELECT id, username, password, email, phone, status, email_verified,
       login_failures, locked_until, created_at, updated_at
FROM user WHERE email = #{email}

SELECT id, username, password, email, phone, status, email_verified,
       login_failures, locked_until, created_at, updated_at
FROM user WHERE phone = #{phone}

mapper.update:
UPDATE user
SET email = #{email}, phone = #{phone}
WHERE id = #{id}
